// ═══════════════════════════════════════════
// ICON RENDERERS
// ═══════════════════════════════════════════
function iconFor(def) {
  switch (def.type) {
    case 'color':
      return `<div class="swatch" style="background:${def.hex};box-shadow:0 2px 8px ${def.hex}55"></div>`;
    case 'text':
      if (def.tag === 'gradient')
        return `<span style="font-size:14px;font-weight:800;background:linear-gradient(90deg,#ff5733,#8338ec);-webkit-background-clip:text;-webkit-text-fill-color:transparent;line-height:1">T</span>`;
      if (def.tag === 'button')
        return `<span style="font-size:9px;padding:2px 5px;border-radius:3px;background:rgba(88,86,214,0.15);color:rgba(88,86,214,0.9);font-weight:600;line-height:1.4;white-space:nowrap">BTN</span>`;
      return `<span style="font-size:${{h1:'16px',p:'12px',small:'9px'}[def.tag]};font-weight:${{h1:'800',p:'400',small:'400'}[def.tag]};color:rgba(0,0,0,0.55);line-height:1">T</span>`;
    case 'shape':  return SHAPE_ICONS[def.shape] || '';
    case 'effect': return `<span style="font-size:16px;line-height:1;color:rgba(0,0,0,0.55)">${EFFECT_ICONS[def.effect]||'◈'}</span>`;
    case 'anim':   return `<span style="font-size:16px;line-height:1;color:rgba(255,59,48,0.85)">${ANIM_ICONS[def.anim]||'◌'}</span>`;
    case 'layout': return `<span style="font-size:15px;line-height:1;color:rgba(52,199,89,0.9)">${LAYOUT_ICONS[def.layout]}</span>`;
    case 'bg':
      return def.subtype === 'gradient'
        ? `<div class="mini-grad" style="background:linear-gradient(135deg,${def.vals[0]},${def.vals[1]})"></div>`
        : `<div class="mini-grad" style="background:${def.val}"></div>`;
    case 'logo':
      return `<img src="${LOGO_DATA_URL}" style="width:20px;height:20px;object-fit:contain;border-radius:3px" draggable="false">`;
  }
  return '';
}

// ═══════════════════════════════════════════
// PALETTE
// ═══════════════════════════════════════════
const PALETTE_MAP = {
  bg:'pb-bg', color:'pb-color', text:'pb-text',
  shape:'pb-shape', anim:'pb-anim', layout:'pb-layout', logo:'pb-logo',
};

function buildPalette() {
  for (const [key, cid] of Object.entries(PALETTE_MAP)) {
    const c = document.getElementById(cid);
    if (!c) continue;
    c.innerHTML = '';
    DEFS[key].forEach((def, i) => {
      const el = makePaletteBlock(def);
      c.appendChild(el);
      gsap.from(el, { x:-12, opacity:0, duration:0.4, delay:0.04*i, ease:'power2.out' });
    });
  }
}

function makePaletteBlock(def) {
  const el = document.createElement('div');
  el.className = `p-block bt-${def.type}`;
  el.draggable = true;
  el.dataset.pid  = def.id;
  el.dataset.tilt = '8';

  const nameHTML = def.type === 'color'
    ? `<span class="mono" style="color:${def.hex === '#FFFFFF' ? '#8E8E93' : def.hex}">${def.hex}</span>`
    : def.label;

  el.innerHTML = `
    <div class="b-icon">${iconFor(def)}</div>
    <div class="b-name">${nameHTML}</div>`;

  el.addEventListener('dragstart', e => {
    dragPal = def.id; dragCIdx = null;
    el.classList.add('is-dragging');
    document.body.classList.add('dragging');
    e.dataTransfer.effectAllowed = 'copy';
    e.dataTransfer.setData('text/plain', def.id);
    gsap.to(el, { scale:0.94, opacity:0.5, duration:0.15 });
  });
  el.addEventListener('dragend', () => {
    el.classList.remove('is-dragging');
    document.body.classList.remove('dragging');
    dragPal = null;
    gsap.to(el, { scale:1, opacity:1, duration:0.25, ease:'back.out(1.5)' });
  });
  el.addEventListener('dblclick', () => addFromPalette(def.id));
  return el;
}

// ═══════════════════════════════════════════
// CANVAS SETUP + DRAG & DROP + REORDER
// ═══════════════════════════════════════════
function setupCanvas() {
  const drop   = document.getElementById('canvasDrop');
  const scroll = document.getElementById('canvasScroll');

  drop.addEventListener('dragover', e => {
    if (dragCIdx !== null) return;
    e.preventDefault();
    drop.classList.add('over');
    e.dataTransfer.dropEffect = 'copy';
  });
  drop.addEventListener('dragleave', e => {
    if (!drop.contains(e.relatedTarget)) drop.classList.remove('over');
  });
  drop.addEventListener('drop', e => {
    e.preventDefault();
    drop.classList.remove('over');
    if (dragPal) addFromPalette(dragPal);
  });

  scroll.addEventListener('dragover', e => {
    if (dragCIdx === null) return;
    e.preventDefault(); e.stopPropagation();
    drop.classList.remove('over');
    const lines    = [...scroll.querySelectorAll('.canvas-drop-line')];
    const wrappers = [...scroll.querySelectorAll('.c-block-wrap')];
    let target = wrappers.length;
    for (let i = 0; i < wrappers.length; i++) {
      const rect = wrappers[i].getBoundingClientRect();
      if (e.clientY < rect.top + rect.height / 2) { target = i; break; }
    }
    if (target !== reorderDropTarget) {
      reorderDropTarget = target;
      lines.forEach((l, i) => l.classList.toggle('active', i === target));
    }
  });

  scroll.addEventListener('dragleave', e => {
    if (!scroll.contains(e.relatedTarget)) {
      reorderDropTarget = -1;
      scroll.querySelectorAll('.canvas-drop-line').forEach(l => l.classList.remove('active'));
    }
  });

  scroll.addEventListener('drop', e => {
    if (dragCIdx === null) return;
    e.preventDefault(); e.stopPropagation();
    scroll.querySelectorAll('.canvas-drop-line').forEach(l => l.classList.remove('active'));
    const from = dragCIdx;
    const to   = reorderDropTarget;
    if (to !== -1 && to !== from && to !== from + 1) {
      const [block] = canvas.splice(from, 1);
      canvas.splice(to > from ? to - 1 : to, 0, block);
      renderCanvas();
    }
    reorderDropTarget = -1;
  });
}

// ═══════════════════════════════════════════
// CANVAS OPS
// ═══════════════════════════════════════════
function findDef(id) {
  for (const arr of Object.values(DEFS)) {
    const f = arr.find(d => d.id === id);
    if (f) return f;
  }
  return null;
}

function addFromPalette(pid) {
  const def = findDef(pid);
  if (!def) return;
  canvas.push({ ...def, iid:`b${++idSeq}` });
  renderCanvas();
}

function removeBlock(iid) {
  const el = document.querySelector(`[data-iid="${iid}"]`);
  if (el) {
    const wrap = el.closest('.c-block-wrap') || el;
    gsap.to(wrap, {
      x:20, opacity:0, height:0, paddingTop:0, paddingBottom:0, marginBottom:0,
      duration:0.25, ease:'power2.in',
      onComplete: () => { canvas = canvas.filter(b => b.iid !== iid); renderCanvas(); }
    });
  } else {
    canvas = canvas.filter(b => b.iid !== iid);
    renderCanvas();
  }
}

// ═══════════════════════════════════════════
// RENDER CANVAS
// ═══════════════════════════════════════════
function escHtml(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

function labelFor(b) {
  switch (b.type) {
    case 'color':  return `<span class="mono" style="color:${b.hex === '#FFFFFF' ? '#8E8E93' : b.hex}">${b.hex}</span>`;
    case 'effect': return EFFECT_LABELS[b.effect] || b.label;
    case 'text':
      if (b.isCustom)
        return `${TAG_LABELS[b.tag]} — <input class="custom-input" data-iid="${b.iid}" placeholder="Raksti šeit..." value="${escHtml(b.customContent||'')}">`;
      return `${TAG_LABELS[b.tag]} <span style="color:var(--t4);font-size:11px">— "${escHtml(b.content)}"</span>`;
    case 'shape':  return `${SHAPE_LABELS[b.shape]||b.shape} <span style="color:var(--t5);font-size:10px">${SIZE_LABELS[b.size]||''}</span>`;
    case 'anim':   return ANIM_LABELS[b.anim];
    case 'layout': return LAYOUT_LABELS[b.layout];
    case 'bg':
      return b.subtype === 'gradient'
        ? `${b.label} <span class="mono" style="font-size:10px;color:var(--t5)">${b.vals[0]} → ${b.vals[1]}</span>`
        : `${b.label} <span class="mono" style="font-size:10px;color:var(--t5)">${b.val}</span>`;
    case 'logo': return `Logo <span style="color:var(--t5);font-size:10px">${SIZE_LABELS[b.size]}</span>`;
  }
  return b.label || '';
}

function renderCanvas() {
  const scroll = document.getElementById('canvasScroll');
  const empty  = document.getElementById('canvasEmpty');
  animateCounter(canvas.length);
  scroll.innerHTML = '';

  if (!canvas.length) { empty.classList.add('show'); checkChallenges(); return; }
  empty.classList.remove('show');

  canvas.forEach((b, idx) => {
    const dropLine = document.createElement('div');
    dropLine.className = 'canvas-drop-line';
    scroll.appendChild(dropLine);

    const wrap = document.createElement('div');
    wrap.className = 'c-block-wrap';

    const el = document.createElement('div');
    el.className = `c-block bt-${b.type}`;
    el.dataset.iid  = b.iid;
    el.dataset.idx  = idx;
    el.dataset.tilt = '5';
    el.draggable    = true;

    el.innerHTML = `
      <div class="b-icon" style="width:24px;height:24px;border-radius:5px">${iconFor(b)}</div>
      <div class="c-block-label">${labelFor(b)}</div>
      <button class="c-block-del" data-iid="${b.iid}" title="Noņemt">
        <svg width="8" height="8" viewBox="0 0 8 8" fill="none" stroke="currentColor"
             stroke-width="1.5" stroke-linecap="round">
          <line x1="1" y1="1" x2="7" y2="7"/><line x1="7" y1="1" x2="1" y2="7"/>
        </svg>
      </button>`;

    if (b.isCustom) {
      const inp = el.querySelector('.custom-input');
      if (inp) {
        inp.addEventListener('input', e => { const blk = canvas.find(x => x.iid === b.iid); if (blk) blk.customContent = e.target.value; });
        inp.addEventListener('mousedown', e => e.stopPropagation());
        inp.addEventListener('dragstart', e => e.stopPropagation());
      }
    }

    el.querySelector('.c-block-del').addEventListener('click', e => { e.stopPropagation(); removeBlock(b.iid); });

    el.addEventListener('dragstart', e => {
      dragCIdx = idx; dragPal = null;
      el.classList.add('dragging-c');
      document.body.classList.add('dragging');
      e.dataTransfer.effectAllowed = 'move';
      gsap.to(el, { scale:0.95, opacity:0.5, duration:0.12 });
    });
    el.addEventListener('dragend', () => {
      el.classList.remove('dragging-c');
      document.body.classList.remove('dragging');
      dragCIdx = null;
      gsap.to(el, { scale:1, opacity:1, duration:0.2 });
      scroll.querySelectorAll('.canvas-drop-line').forEach(l => l.classList.remove('active'));
    });

    wrap.appendChild(el);
    scroll.appendChild(wrap);
    gsap.from(el, { x:-18, opacity:0, scale:0.9, duration:0.4, delay:idx*0.035, ease:'back.out(1.7)', clearProps:'transform' });

    if (idx < canvas.length - 1) {
      const conn = document.createElement('div');
      conn.className = 'c-connector';
      scroll.appendChild(conn);
    }
  });

  const lastLine = document.createElement('div');
  lastLine.className = 'canvas-drop-line';
  scroll.appendChild(lastLine);

  checkChallenges();
}

// ═══════════════════════════════════════════
// CHALLENGES
// ═══════════════════════════════════════════
function isReddish(hex) {
  const r=parseInt(hex.slice(1,3),16), g=parseInt(hex.slice(3,5),16), b=parseInt(hex.slice(5,7),16);
  return r > 170 && g < 120 && b < 120;
}

function checkChallenges() {
  [checkC0(), checkC1(), checkC2()].forEach((pass, i) => {
    const pill   = document.getElementById(`cp${i}`);
    const detail = document.getElementById(`cd${i}`);
    if (!pill) return;
    if (pass) {
      pill.classList.add('done');
      if (detail) detail.classList.add('done');
      if (!doneChallenges.has(i)) {
        doneChallenges.add(i);
        showToast(i);
        gsap.fromTo(pill, { scale:1 }, { scale:1.1, yoyo:true, repeat:3, duration:0.15, ease:'power2.inOut' });
      }
    } else {
      pill.classList.remove('done');
      if (detail) detail.classList.remove('done');
      doneChallenges.delete(i);
    }
  });
}

function checkC0() {
  let red = false;
  for (const b of canvas) {
    if (b.type==='color' && isReddish(b.hex)) red = true;
    if (b.type==='text' && (b.tag==='h1'||b.tag==='gradient') && red) return true;
  }
  return false;
}
function checkC1() {
  return canvas.some(b=>b.type==='shape'  && (b.shape==='circle'||b.shape==='ring')) &&
         canvas.some(b=>b.type==='anim'   && (b.anim==='spin'||b.anim==='spin3d'))   &&
         canvas.some(b=>b.type==='layout' && b.layout==='center');
}
function checkC2() {
  return new Set(canvas.filter(b=>b.type==='color').map(b=>b.hex)).size >= 3;
}

const TOAST_MSGS = [
  { title:'Lieliski!', sub:'Sarkans virsraksts izveidots!' },
  { title:'Izcili!',   sub:'Aplis griežas centrā!'        },
  { title:'Bravo!',    sub:'3 dažādas krāsas lapā!'       },
];
let toastTimer = null;
function showToast(i) {
  const el = document.getElementById('toast');
  document.getElementById('toastTitle').textContent = TOAST_MSGS[i].title;
  document.getElementById('toastSub').textContent   = TOAST_MSGS[i].sub;
  clearTimeout(toastTimer);
  el.classList.add('show');
  toastTimer = setTimeout(() => el.classList.remove('show'), 3800);
}

// ═══════════════════════════════════════════
// CODE GENERATION
// ═══════════════════════════════════════════
const ANIM_KF = {
  fadeIn: `@keyframes fadeIn  { from { opacity:0; transform:translateY(-20px); } to { opacity:1; transform:translateY(0); } }`,
  bounce: `@keyframes bounce  { 0%,100% { transform:translateY(0); } 50% { transform:translateY(-28px); } }`,
  spin:   `@keyframes spin    { from { transform:rotate(0deg); } to { transform:rotate(360deg); } }`,
  pulse:  `@keyframes pulse   { 0%,100% { transform:scale(1); opacity:1; } 50% { transform:scale(1.1); opacity:0.72; } }`,
  float:  `@keyframes float   { 0%,100% { transform:translateY(0); } 50% { transform:translateY(-18px); } }`,
  shake:  `@keyframes shake   { 0%,100% { transform:translateX(0); } 20%,60% { transform:translateX(-10px); } 40%,80% { transform:translateX(10px); } }`,
  spin3d: `@keyframes spin3d  { 0% { transform:perspective(400px) rotateY(0deg); } 100% { transform:perspective(400px) rotateY(360deg); } }`,
};
const ANIM_PROP = {
  fadeIn: 'animation: fadeIn  0.9s cubic-bezier(0.34,1.56,0.64,1) forwards;',
  bounce: 'animation: bounce  1.3s ease-in-out infinite;',
  spin:   'animation: spin    2s linear infinite;',
  pulse:  'animation: pulse   1.6s ease-in-out infinite;',
  float:  'animation: float   3s ease-in-out infinite;',
  shake:  'animation: shake   0.6s ease-in-out infinite;',
  spin3d: 'animation: spin3d  2.5s linear infinite;',
};

function generateCode() {
  const bgBlocks  = canvas.filter(b => b.type==='bg');
  const layBlocks = canvas.filter(b => b.type==='layout');

  let bgCSS = 'background: linear-gradient(135deg, #0f0c29 0%, #302b63 100%);';
  if (bgBlocks.length) {
    const last = bgBlocks[bgBlocks.length-1];
    bgCSS = last.subtype==='gradient'
      ? `background: linear-gradient(135deg, ${last.vals[0]} 0%, ${last.vals[1]} 100%);`
      : `background: ${last.val};`;
  }

  const layMap = { center:{j:'center',a:'center'}, left:{j:'center',a:'flex-start'}, right:{j:'center',a:'flex-end'}, top:{j:'flex-start',a:'center'} };
  let justify='center', align='center';
  if (layBlocks.length) { const lk=layBlocks[layBlocks.length-1].layout; if(layMap[lk]){justify=layMap[lk].j;align=layMap[lk].a;} }
  const textAlign = { center:'center', left:'left', right:'right', top:'center' }[layBlocks.length ? layBlocks[layBlocks.length-1].layout : 'center'] || 'center';

  const elements = [];
  const usedAnims = new Set();
  let curColor='#FFFFFF', curAnim=null, curEffect=null;

  for (const b of canvas) {
    if (b.type==='color')  { curColor=b.hex;    continue; }
    if (b.type==='anim')   { curAnim=b.anim;    continue; }
    if (b.type==='effect') { curEffect=b.effect; continue; }
    if (b.type==='bg' || b.type==='layout') continue;
    if (b.type==='text') {
      const content = b.isCustom ? (b.customContent||'Mans teksts') : b.content;
      if (curAnim) usedAnims.add(curAnim);
      elements.push({ kind:'text', tag:b.tag, content, color:curColor, anim:curAnim, effect:curEffect });
      curAnim=null; curEffect=null;
    }
    if (b.type==='shape') {
      if (curAnim) usedAnims.add(curAnim);
      elements.push({ kind:'shape', shape:b.shape, size:SHP_PX[b.size]||120, color:curColor, anim:curAnim, effect:curEffect });
      curAnim=null; curEffect=null;
    }
    if (b.type==='logo') {
      if (curAnim) usedAnims.add(curAnim);
      elements.push({ kind:'logo', size:LOGO_PX[b.size]||140, anim:curAnim });
      curAnim=null; curEffect=null;
    }
  }

  let elCSS='', elHTML='';
  elements.forEach((el, i) => {
    const cls = `el${i}`;
    const ap  = el.anim ? ANIM_PROP[el.anim] : '';

    if (el.kind==='logo') {
      elCSS  += `    .${cls} { width:${el.size}px; height:auto; object-fit:contain; ${ap} }\n`;
      elHTML += `    <img class="${cls}" src="${LOGO_DATA_URL}" alt="Logo">\n`;
      return;
    }
    if (el.kind==='text') {
      if (el.tag==='button') {
        const glow = el.effect==='neon' ? `box-shadow:0 0 20px ${el.color},0 0 40px ${el.color}44;` : '';
        elCSS  += `    .${cls} { display:inline-block;padding:14px 36px;background:${el.color};color:#fff;font-size:1rem;font-weight:700;border:none;border-radius:50px;cursor:pointer;letter-spacing:0.05em;text-transform:uppercase;box-shadow:0 8px 28px ${el.color}55;${glow}${ap} }\n`;
        elHTML += `    <button class="${cls}">${escHtml(el.content||'Nospied')}</button>\n`;
      } else if (el.tag==='gradient') {
        const shadow = el.effect==='shadow' ? `filter:drop-shadow(0 4px 24px ${el.color}88);` : '';
        elCSS  += `    .${cls} { font-size:3.6rem;font-weight:800;letter-spacing:-0.03em;line-height:1.1;background:linear-gradient(90deg,${el.color},#fff 80%);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;${shadow}${ap} }\n`;
        elHTML += `    <h1 class="${cls}">${escHtml(el.content)}</h1>\n`;
      } else {
        const sh   = el.tag==='h1' ? 'text-shadow:0 2px 40px rgba(0,0,0,0.2);' : '';
        const neon = el.effect==='neon'   ? `text-shadow:0 0 10px ${el.color},0 0 30px ${el.color},0 0 60px ${el.color};` : '';
        const shad = el.effect==='shadow' ? 'text-shadow:4px 4px 20px rgba(0,0,0,0.6);' : '';
        elCSS  += `    .${cls} { color:${el.color};${TEXT_STYLES[el.tag]||''}${sh}${neon||shad}${ap} }\n`;
        elHTML += `    <${el.tag} class="${cls}">${escHtml(el.content)}</${el.tag}>\n`;
      }
    } else if (el.kind==='shape') {
      const sz  = el.size;
      const ng  = el.effect==='neon'    ? `box-shadow:0 0 20px ${el.color},0 0 50px ${el.color}66;` : '';
      const sd  = el.effect==='shadow'  ? 'box-shadow:8px 16px 40px rgba(0,0,0,0.55);' : `box-shadow:0 0 ${Math.round(sz/2.5)}px ${el.color}44;`;
      const gl  = el.effect==='glass'   ? 'background:rgba(255,255,255,0.12);backdrop-filter:blur(16px);border:1px solid rgba(255,255,255,0.3);box-shadow:inset 0 1px 0 rgba(255,255,255,0.3),0 20px 40px rgba(0,0,0,0.3);' : '';
      const ol  = el.effect==='outline' ? `background:transparent;border:3px solid ${el.color};${ng}` : '';
      let sc = '';
      if (el.shape==='circle') {
        sc = el.effect==='glass' ? `width:${sz}px;height:${sz}px;border-radius:50%;${gl}` : el.effect==='outline' ? `width:${sz}px;height:${sz}px;border-radius:50%;${ol}` : `width:${sz}px;height:${sz}px;border-radius:50%;background:${el.color};${el.effect==='neon'?ng:sd}`;
      } else if (el.shape==='ring') {
        sc = `width:${sz}px;height:${sz}px;border-radius:50%;background:transparent;border:${Math.max(4,sz/8)}px solid ${el.color};${el.effect==='neon'?ng:sd}`;
      } else if (el.shape==='square') {
        const r = Math.round(sz*0.14);
        sc = el.effect==='glass' ? `width:${sz}px;height:${sz}px;border-radius:${r}px;${gl}` : el.effect==='outline' ? `width:${sz}px;height:${sz}px;border-radius:${r}px;${ol}` : `width:${sz}px;height:${sz}px;border-radius:${r}px;background:${el.color};${el.effect==='neon'?ng:sd}`;
      } else if (el.shape==='star')    { sc = `width:${sz}px;height:${sz}px;background:${el.color};clip-path:polygon(50% 0%,61% 35%,98% 35%,68% 57%,79% 91%,50% 70%,21% 91%,32% 57%,2% 35%,39% 35%);${el.effect==='neon'?`filter:drop-shadow(0 0 12px ${el.color});`:''}`; }
      else if (el.shape==='hexagon')   { sc = `width:${sz}px;height:${sz}px;background:${el.color};clip-path:polygon(50% 0%,100% 25%,100% 75%,50% 100%,0% 75%,0% 25%);${el.effect==='neon'?`filter:drop-shadow(0 0 12px ${el.color});`:''}`; }
      else if (el.shape==='diamond')   { sc = `width:${sz}px;height:${sz}px;background:${el.color};clip-path:polygon(50% 0%,100% 50%,50% 100%,0% 50%);`; }
      else if (el.shape==='triangle')  { sc = `width:${sz}px;height:${sz}px;background:${el.color};clip-path:polygon(50% 0%,0% 100%,100% 100%);`; }
      elCSS  += `    .${cls} { ${sc} ${ap} }\n`;
      elHTML += `    <div class="${cls}"></div>\n`;
    }
  });

  let animsCSS = '';
  for (const a of usedAnims) animsCSS += `    ${ANIM_KF[a]}\n`;
  if (!elements.length) elHTML = `    <p style="color:rgba(255,255,255,0.1);font-size:1rem;font-weight:300;letter-spacing:0.25em;text-transform:uppercase">Pievieno blokus...</p>\n`;

  return `<!DOCTYPE html>
<html lang="lv">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Mana Lapa</title>
  <style>
    * { margin:0; padding:0; box-sizing:border-box; }
    body {
      ${bgCSS}
      min-height:100vh;
      display:flex; flex-direction:column;
      justify-content:${justify}; align-items:${align};
      font-family:system-ui,-apple-system,sans-serif;
      padding:48px;
    }
    .container {
      display:flex; flex-direction:column;
      align-items:${align}; text-align:${textAlign};
      gap:32px;
    }
${animsCSS}${elCSS}  </style>
</head>
<body>
  <div class="container">
${elHTML}  </div>
</body>
</html>`;
}

// ═══════════════════════════════════════════
// BUILD
// ═══════════════════════════════════════════
function handleBuild() {
  const btn = document.getElementById('btnBuild');
  gsap.timeline()
    .to(btn, { scale:0.94, duration:0.1, ease:'power2.in' })
    .to(btn, { scale:1,    duration:0.5, ease:'elastic.out(1.2,0.5)' });
  btn.disabled = true; btn.textContent = 'Izveido...';

  const pw = document.getElementById('progressWrap');
  const pf = document.getElementById('progressFill');
  pw.classList.add('show'); pf.style.width = '0%';
  requestAnimationFrame(() => requestAnimationFrame(() => { pf.style.width = '100%'; }));

  setTimeout(() => {
    const code = generateCode();
    document.getElementById('previewFrame').srcdoc = code;
    const codeEl = document.getElementById('codeEl');
    codeEl.textContent = code;
    codeEl.removeAttribute('data-highlighted');
    hljs.highlightElement(codeEl);

    const overlay = document.getElementById('modalBg');
    const inner   = document.getElementById('modalInner');
    overlay.classList.add('show');
    gsap.fromTo(inner, { y:55, scale:0.93, opacity:0 }, { y:0, scale:1, opacity:1, duration:0.65, ease:'back.out(1.3)' });

    btn.disabled = false; btn.textContent = 'Izveidot';
    setTimeout(() => { pw.classList.remove('show'); pf.style.width = '0%'; }, 400);
  }, 960);
}

// ═══════════════════════════════════════════
// MODAL
// ═══════════════════════════════════════════
function setupModal() {
  const tabP=document.getElementById('tabPreview'), tabC=document.getElementById('tabCode');
  const panel=document.getElementById('codePanel'), overlay=document.getElementById('modalBg');

  tabP.addEventListener('click', () => {
    tabP.classList.add('active'); tabC.classList.remove('active');
    gsap.to(panel, { x:20, opacity:0, duration:0.25, ease:'power2.in', onComplete:()=>panel.classList.remove('show') });
  });
  tabC.addEventListener('click', () => {
    tabC.classList.add('active'); tabP.classList.remove('active');
    panel.classList.add('show');
    gsap.fromTo(panel, { x:24, opacity:0 }, { x:0, opacity:1, duration:0.45, ease:'back.out(1.4)' });
  });

  function closeModal() {
    gsap.to(document.getElementById('modalInner'), {
      y:30, scale:0.96, opacity:0, duration:0.28, ease:'power2.in',
      onComplete: () => {
        overlay.classList.remove('show'); panel.classList.remove('show');
        tabP.classList.add('active'); tabC.classList.remove('active');
        gsap.set(document.getElementById('modalInner'), { clearProps:'all' });
      }
    });
  }
  document.getElementById('modalClose').addEventListener('click', closeModal);
  document.getElementById('tlClose').addEventListener('click', closeModal);
  overlay.addEventListener('click', e => { if(e.target===overlay) closeModal(); });
  document.addEventListener('keydown', e => { if(e.key==='Escape') closeModal(); });
}

// ═══════════════════════════════════════════
// VISUAL EFFECTS — optimized
// ═══════════════════════════════════════════

// Aurora canvas — 5 blobs, skips every other frame (~30fps)
function initAurora() {
  const cvs = document.getElementById('auroraCanvas');
  const ctx  = cvs.getContext('2d', { alpha: true });
  const BLOBS = [
    { rgb:[10,132,255],  opacity:0.08, r:380, vx:0.28,  vy:0.18  },
    { rgb:[94,92,230],   opacity:0.06, r:340, vx:-0.22, vy:0.24  },
    { rgb:[48,209,88],   opacity:0.04, r:300, vx:0.18,  vy:-0.22 },
    { rgb:[255,55,95],   opacity:0.05, r:280, vx:-0.26, vy:-0.16 },
    { rgb:[100,210,255], opacity:0.04, r:260, vx:0.20,  vy:0.28  },
  ];
  function resize() {
    cvs.width = window.innerWidth; cvs.height = window.innerHeight;
    BLOBS.forEach(b => { if (!b.x) { b.x = Math.random()*cvs.width; b.y = Math.random()*cvs.height; } });
  }
  window.addEventListener('resize', resize); resize();
  let frame = 0;
  (function tick() {
    requestAnimationFrame(tick);
    if (++frame % 2 !== 0) return;
    ctx.clearRect(0, 0, cvs.width, cvs.height);
    for (const b of BLOBS) {
      b.x += b.vx; b.y += b.vy;
      if (b.x < -b.r) b.x = cvs.width  + b.r; if (b.x > cvs.width  + b.r) b.x = -b.r;
      if (b.y < -b.r) b.y = cvs.height + b.r; if (b.y > cvs.height + b.r) b.y = -b.r;
      const [r,g,bl] = b.rgb;
      const gr = ctx.createRadialGradient(b.x, b.y, 0, b.x, b.y, b.r);
      gr.addColorStop(0,    `rgba(${r},${g},${bl},${b.opacity})`);
      gr.addColorStop(0.45, `rgba(${r},${g},${bl},${(b.opacity*0.3).toFixed(3)})`);
      gr.addColorStop(1,    `rgba(${r},${g},${bl},0)`);
      ctx.beginPath(); ctx.arc(b.x, b.y, b.r, 0, Math.PI*2);
      ctx.fillStyle = gr; ctx.fill();
    }
  })();
}


// 3D Tilt — single delegated listener, RAF-throttled, data-tilt attribute on elements
function initTilt() {
  let mx=0, my=0, pending=false, target=null;
  document.addEventListener('mousemove', e => {
    mx = e.clientX; my = e.clientY;
    if (!pending && target) {
      pending = true;
      requestAnimationFrame(() => {
        if (target) {
          const rect = target.getBoundingClientRect();
          const intensity = parseFloat(target.dataset.tilt) || 8;
          const dx = ((mx - rect.left) / rect.width  - 0.5) * 2;
          const dy = ((my - rect.top)  / rect.height - 0.5) * 2;
          gsap.to(target, { rotateY:dx*intensity, rotateX:-dy*intensity, duration:0.22, ease:'power2.out', transformPerspective:700 });
        }
        pending = false;
      });
    }
  });
  document.addEventListener('mouseover', e => {
    const el = e.target.closest('[data-tilt]');
    if (el) { target = el; el.style.transformStyle = 'preserve-3d'; }
  });
  document.addEventListener('mouseout', e => {
    const el = e.target.closest('[data-tilt]');
    if (el && !el.contains(e.relatedTarget)) {
      if (target === el) target = null;
      gsap.to(el, { rotateY:0, rotateX:0, duration:0.65, ease:'elastic.out(1,0.55)' });
    }
  });
}

// Ripple on click
function addRipple(btn) {
  btn.addEventListener('pointerdown', e => {
    const rect = btn.getBoundingClientRect();
    const span = document.createElement('span');
    span.className = 'ripple';
    span.style.left = `${e.clientX - rect.left}px`;
    span.style.top  = `${e.clientY - rect.top}px`;
    span.style.marginLeft = '-2px'; span.style.marginTop = '-2px';
    btn.appendChild(span);
    gsap.to(span, { scale:90, opacity:0, duration:0.65, ease:'power2.out', onComplete:()=>span.remove() });
  });
}

// Animated block counter
function animateCounter(to) {
  const el   = document.getElementById('blockCount');
  const from = parseInt(el.textContent, 10) || 0;
  if (from === to) return;
  const obj = { val: from };
  gsap.to(obj, { val:to, duration:0.4, ease:'power2.out', onUpdate:()=>{ el.textContent = Math.round(obj.val); } });
}

// ═══════════════════════════════════════════
// INIT
// ═══════════════════════════════════════════
function init() {
  initAurora();
  initTilt();
  buildPalette();
  setupCanvas();
  setupModal();

  addRipple(document.getElementById('btnBuild'));
  addRipple(document.getElementById('btnClear'));

  gsap.from('#appHeader',  { y:-18, opacity:0, duration:0.5, ease:'power3.out' });
  gsap.from('#paletteEl',  { x:-22, opacity:0, duration:0.5, delay:0.07, ease:'power3.out' });
  gsap.from('#canvasArea', { opacity:0, duration:0.5, delay:0.12, ease:'power2.out' });

  // Inject actual logo into header
  const headerLogo = document.getElementById('headerLogo');
  if (headerLogo) {
    const img = document.createElement('img');
    img.src = LOGO_DATA_URL;
    img.alt = 'Logo';
    headerLogo.appendChild(img);
  }

  canvas = [
    { ...DEFS.bg[0],     iid:`b${++idSeq}` },
    { ...DEFS.layout[0], iid:`b${++idSeq}` },
    { ...DEFS.logo[0],   iid:`b${++idSeq}` },
    { ...DEFS.color[5],  iid:`b${++idSeq}` },
    { ...DEFS.text[0],   iid:`b${++idSeq}` },
  ];
  renderCanvas();

  document.getElementById('btnBuild').addEventListener('click', handleBuild);
  document.getElementById('btnClear').addEventListener('click', () => {
    canvas = []; doneChallenges.clear();
    document.querySelectorAll('.c-pill').forEach(p => p.classList.remove('done'));
    gsap.to('#canvasScroll', { opacity:0, duration:0.2, onComplete:() => { renderCanvas(); gsap.to('#canvasScroll', { opacity:1, duration:0.3 }); } });
  });
}

document.addEventListener('DOMContentLoaded', init);
